import { createComponentLogger } from '../../utils/component-logger.js';

/**
 * localStorage key shared with the inline boot script in `index.html`.
 *
 * That inline script runs *before* the app module loads, so it survives the
 * black-screen-on-resume failure where no app code ever executes (and thus no
 * client log is produced). It appends one breadcrumb per document load —
 * navigation type, isolation, whether a SW controls the page, and the
 * `servedAs` marker ('index' vs the generated '404' SPA fallback). This module
 * ships and clears those breadcrumbs on the next *successful* boot, so the
 * otherwise-invisible failed loads ride along on the first load that works.
 *
 * Keep this string in sync with `index.html`'s inline script. See design_log #156.
 */
export const BOOT_BREADCRUMBS_KEY = 'boot_breadcrumbs';

const log = createComponentLogger('boot');

/**
 * Ship any boot breadcrumbs left in localStorage through the normal client-log
 * pipeline, then clear them. Called once at startup, after console capture is
 * installed. Best-effort: storage or parse failures are swallowed so telemetry
 * can never break boot.
 */
export function flushBootBreadcrumbs(storage: Storage = localStorage): void {
    let raw: string | null;
    try {
        raw = storage.getItem(BOOT_BREADCRUMBS_KEY);
    } catch {
        return;
    }
    if (!raw) return;

    // Clear first: a duplicate breadcrumb is harmless, but re-shipping forever
    // because logging threw would not be.
    try {
        storage.removeItem(BOOT_BREADCRUMBS_KEY);
    } catch {
        // ignore — still ship what we read below
    }

    let crumbs: unknown;
    try {
        crumbs = JSON.parse(raw);
    } catch {
        log.warn('boot breadcrumbs: discarded unparseable buffer', raw);
        return;
    }
    if (!Array.isArray(crumbs) || crumbs.length === 0) return;

    for (const crumb of crumbs) {
        log.info('boot breadcrumb', crumb);
    }
}
