/**
 * Last-resort visible error screen for boot-time failures (story 183).
 *
 * Rendered by main.ts when the app module fails to load or throws during
 * evaluation — e.g. config.ts's MOTIVATION_API_STRICT guard. At that point no
 * router, no components, and possibly no stylesheets exist, so this module
 * must depend on nothing: plain DOM, inline colors (the dark body background
 * from index.html would otherwise render black-on-black), raw stack output.
 */

interface BootFailureOptions {
    doc?: Document;
    reload?: () => void;
}

export function renderBootFailure(err: unknown, options: BootFailureOptions = {}): void {
    const doc = options.doc ?? document;
    const reload = options.reload ?? (() => doc.location.reload());

    const heading = doc.createElement('h1');
    heading.textContent = 'App failed to start';

    const pre = doc.createElement('pre');
    pre.className = 'screen-error';
    pre.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
    pre.style.whiteSpace = 'pre-wrap';
    pre.style.color = '#ff6b6b';

    const button = doc.createElement('button');
    button.className = 'screen-retry';
    button.textContent = 'Reload';
    button.addEventListener('click', () => reload());

    doc.body.replaceChildren(heading, pre, button);
    doc.body.style.color = '#eee';
    doc.body.style.padding = '1rem';
}
