import { installConsoleCapture } from './services/debug/client-log-buffer.js';
import { flushBootBreadcrumbs } from './services/debug/boot-breadcrumbs.js';
// Hoisting above installConsoleCapture() is safe: boot-failure imports nothing
// and does nothing at module scope.
import { renderBootFailure } from './services/debug/boot-failure.js';

// Install log capture before importing anything else so the /debug screen
// sees boot-time events. app.js is imported dynamically for this reason —
// static imports would be hoisted above this call.
installConsoleCapture();

// Ship breadcrumbs left by the inline boot script in index.html (which runs
// even when this module fails to load). Failed/black-screen resumes leave no
// app logs of their own; their breadcrumbs surface here on the first boot that
// actually reaches app code. See design_log #156.
flushBootBreadcrumbs();

// A failed app import (chunk load error, or a module-scope throw such as
// config.ts's MOTIVATION_API_STRICT guard) previously left a blank page —
// upstream of the router's error isolation. Render the raw error instead
// (fail loud, story 183).
try {
    const { startApp } = await import('./app.js');
    startApp();
} catch (err) {
    console.error('[boot] app failed to start:', err);
    renderBootFailure(err);
}
